date_range_calculation.template:
const moment = require('moment-timezone');
function generateDateRanges(start, end, intervalDays) {
  const ranges = [];
  let current = moment(start);
  const endDate = moment(end);

  while (current.isBefore(endDate)) {
    const rangeEnd = moment.min(current.clone().add(intervalDays, 'days'), endDate);
    ranges.push({
      start: current.format('YYYY-MM-DD'),
      end: rangeEnd.format('YYYY-MM-DD')
    });
    current = rangeEnd.add(1, 'day');
  }

  return ranges;
}

